import os
import sqlite3
import shutil
from flask import Flask, request, jsonify, render_template, abort
from urllib.parse import unquote

app = Flask(__name__)
app.config.from_object('config.Config')

# Path for the runtime database in /tmp
DB_PATH = '/tmp/aetheris.db'
ORIGINAL_DB = '/app/aetheris.db'

def get_db():
    # Copy the database to /tmp if it doesn't exist (read-only FS workaround)
    if not os.path.exists(DB_PATH):
        shutil.copy(ORIGINAL_DB, DB_PATH)
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def waf_check(payload):
    if not payload:
        return True
    # Defense 1: Strict keyword blacklist (case-insensitive)
    blacklist = ['SELECT', 'FROM', 'WHERE', 'UNION', 'ALL', 'UPDATE', 'INSERT', 'DELETE', 'OR', 'AND', '--', '/*']
    upper_payload = payload.upper()
    for word in blacklist:
        if word in upper_payload:
            return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/dashboard')
def dashboard():
    return render_template('dashboard.html')

@app.route('/satellites')
def satellites():
    db = get_db()
    satellites = db.execute('SELECT * FROM satellites').fetchall()
    return render_template('satellites.html', satellites=satellites)

@app.route('/payloads')
def payloads():
    db = get_db()
    payloads = db.execute('SELECT p.*, s.name as sat_name FROM payloads p JOIN satellites s ON p.satellite_id = s.id').fetchall()
    return render_template('payloads.html', payloads=payloads)

@app.route('/telemetry')
def telemetry():
    db = get_db()
    logs = db.execute('SELECT l.*, s.name as sat_name FROM telemetry_logs l JOIN satellites s ON l.satellite_id = s.id LIMIT 20').fetchall()
    return render_template('telemetry.html', logs=logs)

@app.route('/api/v2/telemetry/export')
def export_telemetry():
    # Step 1: Authentication via Header
    auth_token = request.headers.get('X-AOD-Debug-Token')
    if auth_token != "aod-dev-2023-debug-manifest":
        return jsonify({"error": "Unauthorized. Internal debug token required."}), 403

    # Step 2: Input Acquisition
    sort_idx = request.args.get('sort_idx', 'id')

    # Defense 2: WAF check on raw input
    if not waf_check(sort_idx):
        return jsonify({"error": "Security Alert: Malicious SQL keywords detected."}), 400

    # Defense 3: Normalization Flaw (Double decoding for legacy support)
    # This is the expert-level vulnerability: the WAF runs on once-decoded input, but the query uses twice-decoded input
    normalized_sort = unquote(unquote(sort_idx))

    try:
        db = get_db()
        # Vulnerable ORDER BY concatenation
        query = f"SELECT id, name, status FROM satellites ORDER BY {normalized_sort}"
        results = db.execute(query).fetchall()
        return jsonify([dict(row) for row in results])
    except Exception as e:
        # No leaks in production
        return jsonify({"error": "Internal processing error in legacy engine."}), 500

@app.route('/api/v2/status')
def status():
    return jsonify({"status": "Operational", "version": "2.4.1-legacy"})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

